// <auto-generated>
// Auth0 JWT (RS256) validation for inbound API requests -- the Rust
// counterpart of the .NET API server's AddJwtBearer(...) configuration in
// Program.cs.cshtml (see docs/auth0-setup.md).
//
// Domain/Audience are read at *runtime* from this application's own
// ~/.<namespace>.json (an `auth0` section alongside the existing
// `datasources`/`loglevel`/`logwriters` entries -- see
// common::config::NamespaceConfig / Config::auth0_settings), not baked in at
// generation time. One jumpstart install generates many different
// applications from a single ~/.jumpstart.json, so a per-namespace runtime
// file -- the same one already used for each app's database connection -- is
// the right place for per-application settings like an Auth0 tenant/audience,
// not the generator's own shared config.
//
// If the `auth0` section is absent, or `domain`/`audience` are empty, Auth0
// is treated as unconfigured and the caller (main.generated.rs) falls back to
// the pre-Auth0 `X-User` header, so `jumptest` / local development keeps
// working without a real Auth0 tenant. Once both are set, every request must
// carry a valid Bearer token.
// </auto-generated>
#![allow(dead_code)]

use std::sync::{Mutex, OnceLock};
use std::time::{Duration, Instant};

use common::Config;
use jsonwebtoken::{decode, decode_header, Algorithm, DecodingKey, Validation};
use serde::Deserialize;
use serde_json::Value;

/// True once this application's `~/.<namespace>.json` has a non-empty
/// `auth0` section (`domain` and `audience` both set).
pub fn is_configured() -> bool {
    Config::auth0_settings().is_some()
}

/// Outcome of authenticating one inbound request.
pub enum AuthOutcome {
    /// Auth0 is not configured; caller should fall back to the X-User header.
    Unconfigured,
    /// A valid JWT was presented; carries the principal (email, or `sub` if
    /// no email claim was found) to set as the current user.
    Authenticated(String),
    /// Auth0 is configured but the request carried no bearer token at all.
    Missing,
    /// A bearer token was presented but failed validation (bad signature,
    /// expired, wrong audience/issuer, unknown signing key, ...). Carries a
    /// human-readable reason for logging; callers should reject with 401.
    Invalid(String),
}

#[derive(Debug, Clone, Deserialize)]
struct Jwks {
    keys: Vec<Jwk>,
}

#[derive(Debug, Clone, Deserialize)]
struct Jwk {
    kid: String,
    kty: String,
    n: String,
    e: String,
}

/// How long a fetched JWKS is trusted before being re-fetched on a schedule
/// (Auth0 rotates signing keys infrequently; this just bounds staleness).
const JWKS_TTL: Duration = Duration::from_secs(600);

fn jwks_cache() -> &'static Mutex<Option<(Instant, Vec<Jwk>)>> {
    static CACHE: OnceLock<Mutex<Option<(Instant, Vec<Jwk>)>>> = OnceLock::new();
    CACHE.get_or_init(|| Mutex::new(None))
}

/// Fetch (or return the cached copy of) the tenant's signing keys from
/// `https://{domain}/.well-known/jwks.json`. Pass `force_refresh` to bypass
/// the TTL -- used once when a token's `kid` isn't found in the cache, so a
/// freshly rotated Auth0 signing key is picked up without waiting for the
/// next scheduled refresh.
fn jwks(domain: &str, force_refresh: bool) -> Result<Vec<Jwk>, String> {
    {
        let cache = jwks_cache().lock().unwrap();
        if !force_refresh {
            if let Some((fetched_at, keys)) = cache.as_ref() {
                if fetched_at.elapsed() < JWKS_TTL {
                    return Ok(keys.clone());
                }
            }
        }
    }

    let url = format!("https://{}/.well-known/jwks.json", domain);
    let body_str = ureq::get(&url)
        .call()
        .map_err(|e| format!("JWKS fetch from {} failed: {}", url, e))?
        .into_string()
        .map_err(|e| format!("JWKS response from {} unreadable: {}", url, e))?;
    let body: Jwks = serde_json::from_str(&body_str)
        .map_err(|e| format!("JWKS response from {} not valid JSON: {}", url, e))?;

    *jwks_cache().lock().unwrap() = Some((Instant::now(), body.keys.clone()));
    Ok(body.keys)
}

/// Validate the `Authorization: Bearer <token>` header (if present) against
/// Auth0's JWKS and this app's configured audience/issuer (both read from
/// `~/.<namespace>.json`), returning the principal to use for the
/// logic-layer authorization check.
///
/// Mirrors the .NET pipeline: JwtBearer validates signature/audience/issuer/
/// expiry, then the identity-propagation middleware in Program.cs picks
/// `https://claims/email` (added by the Post-Login Action in
/// docs/auth0-setup.md step 7), falling back to the standard `email` claim
/// and finally the Auth0 subject (`sub`).
pub fn authenticate(auth_header: Option<&str>) -> AuthOutcome {
    let auth0 = match Config::auth0_settings() {
        Some(a) => a,
        None => return AuthOutcome::Unconfigured,
    };

    let token = match auth_header.and_then(strip_bearer_prefix) {
        Some(t) if !t.is_empty() => t,
        _ => return AuthOutcome::Missing,
    };

    let header = match decode_header(token) {
        Ok(h) => h,
        Err(e) => return AuthOutcome::Invalid(format!("malformed token header: {}", e)),
    };
    let kid = match header.kid {
        Some(k) => k,
        None => return AuthOutcome::Invalid("token header missing 'kid'".to_string()),
    };

    // Try the cached JWKS first; on a cache miss, force one refresh (covers
    // Auth0 signing-key rotation) before giving up.
    let mut keys = match jwks(&auth0.domain, false) {
        Ok(k) => k,
        Err(e) => return AuthOutcome::Invalid(e),
    };
    if !keys.iter().any(|k| k.kid == kid) {
        keys = match jwks(&auth0.domain, true) {
            Ok(k) => k,
            Err(e) => return AuthOutcome::Invalid(e),
        };
    }
    let jwk = match keys.iter().find(|k| k.kid == kid) {
        Some(k) => k,
        None => return AuthOutcome::Invalid(format!("no signing key found for kid '{}'", kid)),
    };
    if jwk.kty != "RSA" {
        return AuthOutcome::Invalid(format!("unsupported signing key type '{}'", jwk.kty));
    }

    let decoding_key = match DecodingKey::from_rsa_components(&jwk.n, &jwk.e) {
        Ok(k) => k,
        Err(e) => return AuthOutcome::Invalid(format!("bad signing key: {}", e)),
    };

    let mut validation = Validation::new(Algorithm::RS256);
    validation.set_audience(&[auth0.audience.as_str()]);
    validation.set_issuer(&[format!("https://{}/", auth0.domain)]);

    let claims = match decode::<Value>(token, &decoding_key, &validation) {
        Ok(data) => data.claims,
        Err(e) => return AuthOutcome::Invalid(format!("token validation failed: {}", e)),
    };

    let username = claim_str(&claims, "https://claims/email")
        .or_else(|| claim_str(&claims, "email"))
        .or_else(|| claim_str(&claims, "sub"));

    match username {
        Some(u) => AuthOutcome::Authenticated(u),
        None => AuthOutcome::Invalid("token has no email or sub claim".to_string()),
    }
}

fn strip_bearer_prefix(header: &str) -> Option<&str> {
    header
        .strip_prefix("Bearer ")
        .or_else(|| header.strip_prefix("bearer "))
        .map(str::trim)
}

fn claim_str(claims: &Value, key: &str) -> Option<String> {
    claims.get(key).and_then(Value::as_str).map(str::to_string)
}
